def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    median_index = len(nums) // 2
    min_drop, max_drop = min(nums[:median_index]), max(nums[median_index:])
    return sum(nums)[median_index - 1 : median_index + 1] / (len(nums) - 2) - ((min_drop + max_drop) / 2)
